class Solution(object):
    def longestSemiRepetitiveSubstring(self, s):
        n = len(s)
        ans = 1
        left = 0
        pairs = 0  # count of adjacent equal pairs in window
        for right in range(1, n):
            if s[right] == s[right-1]:
                pairs += 1
            while pairs > 1:
                if s[left] == s[left+1]:
                    pairs -= 1
                left += 1
            ans = max(ans, right - left + 1)
        return ans
